module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
) (
    input  wire                 wclk,
    input  wire                 wenc,
    input  wire [$clog2(DEPTH)-1:0] waddr,
    input  wire [WIDTH-1:0]     wdata,
    input  wire                 rclk,
    input  wire                 renc,
    input  wire [$clog2(DEPTH)-1:0] raddr,
    output wire [WIDTH-1:0]     rdata
);

    reg [WIDTH-1:0] mem [DEPTH-1:0];
    reg [$clog2(DEPTH)-1:0] wp;
    reg [$clog2(DEPTH)-1:0] rp;
    reg [WIDTH-1:0] rd;

    always @(posedge wclk) begin
        if (wenc) begin
            mem[waddr] <= wdata;
            wp <= (wp == DEPTH-1) ? 0 : wp + 1;
        end
    end

    always @(posedge rclk) begin
        if (renc) begin
            rd <= mem[raddr];
            rp <= (rp == DEPTH-1) ? 0 : rp + 1;
        end
    end

    assign rdata = rd;

endmodule
